 1	import React, { FC } from 'react';
 2	import { NodeModelGroupVersionKind } from 'src/console-models/NodeModel';
 3	
 4	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 5	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 6	import {
 7	  Alert,
 8	  AlertVariant,
 9	  Button,
10	  Flex,
11	  FlexItem,
12	  pluralize,
13	  Popover,
14	} from '@patternfly/react-core';
15	import Loading from '@utils/components/Loading/Loading';
16	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
17	
18	type NodeCheckerAlertProps = {
19	  qualifiedNodes: IoK8sApiCoreV1Node[];
20	  nodesLoaded: boolean;
21	};
22	
23	const NodeCheckerAlert: FC<NodeCheckerAlertProps> = ({ qualifiedNodes, nodesLoaded }) => {
24	  const { t } = useNMStateTranslation();
25	  if (!nodesLoaded) {
26	    return <Loading />;
27	  }
28	
29	  const qualifiedNodesSize = qualifiedNodes?.length || 0;
30	
31	  const matchingNodeText = pluralize(qualifiedNodesSize, 'Node');
32	
33	  let nodes = [];
34	  if (qualifiedNodesSize) {
35	    nodes = qualifiedNodes;
36	  }
37	
38	  return (
39	    <Alert
40	      title={
41	        <>
42	          {qualifiedNodesSize ? (
43	            <>
44	              {t('{{matchingNodeText}} matching', {
45	                matchingNodeText,
46	              })}
47	            </>
48	          ) : (
49	            t('No matching Nodes found for the labels')
50	          )}
51	        </>
52	      }
53	      variant={qualifiedNodesSize ? AlertVariant.success : AlertVariant.warning}
54	      isInline
55	    >
56	      {qualifiedNodesSize ? (
57	        <Popover
58	          headerContent={
59	            <>
60	              {t('{{qualifiedNodesCount}} matching Nodes found', {
61	                qualifiedNodesCount: qualifiedNodesSize,
62	              })}
63	            </>
64	          }
65	          bodyContent={
66	            <>
67	              {nodes?.map((node) => (
68	                <Flex key={node.metadata.uid}>
69	                  <FlexItem spacer={{ default: 'spacerXs' }}>
70	                    <ResourceLink
71	                      groupVersionKind={NodeModelGroupVersionKind}
72	                      name={node.metadata.name}
73	                    />
74	                  </FlexItem>
75	                </Flex>
76	              ))}
77	            </>
78	          }
79	        >
80	          <Button variant="link" isInline>
81	            {t('View matching Nodes')}
82	          </Button>
83	        </Popover>
84	      ) : (
85	        t('Scheduling will not be possible at this state')
86	      )}
87	    </Alert>
88	  );
89	};
90	
91	export default NodeCheckerAlert;

